+                Event::PatternDetected {
+                    detection,
+                    event_id: Some(id),
+                    ..
+                } => {
+                    assert_eq!(detection.rule_id, "rule-x");
+                    assert_eq!(id, 99);
+                }
+                other => panic!("expected PatternDetected, got: {other:?}"),
